SELECT ci.CART_ITEM_ID, ci.CART_ID, ci.PRODUCT_ID, ci.OPTION_ID, p.PRODUCT_NAME, p.BRAND_NAME, p.BIZ_NO, f.FILE_URL AS THUMBNAIL_URL, o.OPTION_COLOR, o.OPTION_SIZE, TO_NUMBER(ci.QTY) AS QTY, TO_NUMBER(ci.PRICE) AS PRICE, o.STOCK_QTY FROM TB_CART_ITEM ci
JOIN TB_PRODUCT p ON p.PRODUCT_ID = ci.PRODUCT_ID LEFT JOIN TB_PRODUCT_OPTION o ON o.OPTION_ID = ci.OPTION_ID LEFT JOIN ( SELECT REF_ID, FILE_URL, ROW_NUMBER() OVER (PARTITION BY REF_ID ORDER BY FILE_ID) AS RN FROM TB_FILE WHERE REF_TYPE = 'PRODUCT' ) f ON f.REF_ID = ci.PRODUCT_ID AND f.RN = 1 WHERE ci.CART_ITEM_ID IN
#{id}

